export function getTechQuestions(techSlug: string) {
  return QUESTIONS[techSlug];
}

export function getLevelQuestions(techSlug: string, level: ELearningLevel) {
  return QUESTIONS[techSlug]?.[level] ?? [];
}

export function getCountsFromQuestions(techSlug: string) {
  const tech = QUESTIONS[techSlug];

  if (!tech) return { basic: 0, intermediate: 0, advanced: 0 };

  return {
    basic: tech.basic.length,
    intermediate: tech.intermediate.length,
    advanced: tech.advanced.length
  };
}
